using System.Diagnostics;
using System.Runtime.CompilerServices;
using TextAnalysis;

// Build a ~10k-word corpus
var baseWords = new[] {
    "the", "quick", "brown", "fox", "jumps", "over", "lazy", "dog",
    "performance", "benchmarking", "is", "important", "for", "software",
    "engineering", "dotnet", "runtime", "optimization", "garbage", "collection",
    "a", "an", "extraordinary", "accomplishment", "testing"
};
var rng = new Random(42);
var parts = new string[10_000];
for (int i = 0; i < parts.Length; i++)
    parts[i] = baseWords[rng.Next(baseWords.Length)];
var analyzer = new TextAnalyzer(string.Join(" ", parts));

Console.WriteLine($"Runtime: {System.Runtime.InteropServices.RuntimeInformation.FrameworkDescription}");
Console.WriteLine($"Words: {analyzer.WordCount}");
Console.WriteLine();

const int warmupIterations = 500;
const int measuredIterations = 5000;

RunBenchmark("AverageWordLength", () => analyzer.AverageWordLength());
RunBenchmark("WordLengthHistogram", () => analyzer.WordLengthHistogram());
RunBenchmark("UniqueWordCount", () => analyzer.UniqueWordCount());

[MethodImpl(MethodImplOptions.NoInlining)]
static void RunBenchmark(string name, Func<object?> action)
{
    // Warmup
    for (int i = 0; i < warmupIterations; i++)
        action();
    GC.Collect();
    GC.WaitForPendingFinalizers();
    GC.Collect();

    // Measure multiple rounds to get stable stats
    const int rounds = 5;
    var roundMeans = new double[rounds];

    for (int r = 0; r < rounds; r++)
    {
        var sw = Stopwatch.StartNew();
        for (int i = 0; i < measuredIterations; i++)
            action();
        sw.Stop();
        roundMeans[r] = sw.Elapsed.TotalNanoseconds / measuredIterations;
    }

    Array.Sort(roundMeans);
    double median = roundMeans[rounds / 2];
    double min = roundMeans[0];
    double max = roundMeans[rounds - 1];

    Console.WriteLine($"{name,-25} | Median: {FormatNs(median),12} | Min: {FormatNs(min),12} | Max: {FormatNs(max),12}");
}

static string FormatNs(double ns)
{
    if (ns < 1_000) return $"{ns:F1} ns";
    if (ns < 1_000_000) return $"{ns / 1_000:F2} μs";
    return $"{ns / 1_000_000:F2} ms";
}

